namespace sv_61594a677efa4f198e007d902b81bae0.Models;

public class Product
{
    public int Id { get; set; }
    public string Name { get; set; } = string.Empty;
    public int Quantity { get; set; }
    public decimal UnitPrice { get; set; }
    public string Category { get; set; } = string.Empty;
}

using sv_61594a677efa4f198e007d902b81bae0.Models;

namespace sv_61594a677efa4f198e007d902b81bae0.Services;

public class InventoryService
{
    private readonly List<Product> _products = new()
    {
        new Product { Id = 1, Name = "Wireless Mouse", Quantity = 150, UnitPrice = 29.99m, Category = "Electronics" },
        new Product { Id = 2, Name = "Cotton T-Shirt", Quantity = 300, UnitPrice = 14.99m, Category = "Clothing" },
        new Product { Id = 3, Name = "Organic Almonds", Quantity = 75, UnitPrice = 8.49m, Category = "Food" },
        new Product { Id = 4, Name = "USB-C Cable", Quantity = 500, UnitPrice = 12.99m, Category = "Electronics" },
        new Product { Id = 5, Name = "Winter Jacket", Quantity = 60, UnitPrice = 89.99m, Category = "Clothing" },
        new Product { Id = 6, Name = "Notebook & Pen Set", Quantity = 200, UnitPrice = 5.99m, Category = "Other" }
    };

    private readonly Lock _lock = new();

    public Task<List<Product>> GetAllAsync()
    {
        lock (_lock)
        {
            var copy = _products.Select(p => new Product
            {
                Id = p.Id,
                Name = p.Name,
                Quantity = p.Quantity,
                UnitPrice = p.UnitPrice,
                Category = p.Category
            }).ToList();
            return Task.FromResult(copy);
        }
    }

    public Task UpdateAsync(Product product)
    {
        lock (_lock)
        {
            var existing = _products.FirstOrDefault(p => p.Id == product.Id);
            if (existing is not null)
            {
                existing.Name = product.Name;
                existing.Quantity = product.Quantity;
                existing.UnitPrice = product.UnitPrice;
                existing.Category = product.Category;
            }
        }
        return Task.CompletedTask;
    }
}

@page "/inventory"
@rendermode InteractiveServer
@using sv_61594a677efa4f198e007d902b81bae0.Models
@using sv_61594a677efa4f198e007d902b81bae0.Services
@inject InventoryService InventoryService

<PageTitle>Inventory</PageTitle>

<h1>Inventory</h1>

@if (_products is null)
{
    <p><em>Loading...</em></p>
}
else
{
    <table class="table">
        <thead>
            <tr>
                <th>Name</th>
                <th>Quantity</th>
                <th>Unit Price</th>
                <th>Category</th>
                <th>Actions</th>
            </tr>
        </thead>
        <tbody>
            @foreach (var product in _products)
            {
                @if (_editingProductId == product.Id)
                {
                    <tr>
                        <td>
                            <input type="text" class="form-control" @bind="_editName" />
                            @if (!string.IsNullOrEmpty(_nameError))
                            {
                                <div class="text-danger small">@_nameError</div>
                            }
                        </td>
                        <td>
                            <input type="number" class="form-control" @bind="_editQuantity" />
                            @if (!string.IsNullOrEmpty(_quantityError))
                            {
                                <div class="text-danger small">@_quantityError</div>
                            }
                        </td>
                        <td>
                            <input type="number" class="form-control" step="0.01" @bind="_editUnitPrice" />
                            @if (!string.IsNullOrEmpty(_priceError))
                            {
                                <div class="text-danger small">@_priceError</div>
                            }
                        </td>
                        <td>
                            <select class="form-select" @bind="_editCategory">
                                <option value="">-- Select --</option>
                                @foreach (var cat in Categories)
                                {
                                    <option value="@cat">@cat</option>
                                }
                            </select>
                            @if (!string.IsNullOrEmpty(_categoryError))
                            {
                                <div class="text-danger small">@_categoryError</div>
                            }
                        </td>
                        <td>
                            <button class="btn btn-success btn-sm me-1" @onclick="SaveAsync">Save</button>
                            <button class="btn btn-secondary btn-sm" @onclick="Cancel">Cancel</button>
                        </td>
                    </tr>
                }
                else
                {
                    <tr>
                        <td>@product.Name</td>
                        <td>@product.Quantity</td>
                        <td>@product.UnitPrice.ToString("C")</td>
                        <td>@product.Category</td>
                        <td>
                            <button class="btn btn-primary btn-sm" @onclick="() => StartEdit(product)">Edit</button>
                        </td>
                    </tr>
                }
            }
        </tbody>
    </table>
}

@code {
    private List<Product>? _products;
    private int? _editingProductId;

    private string _editName = string.Empty;
    private int _editQuantity;
    private decimal _editUnitPrice;
    private string _editCategory = string.Empty;

    private string? _nameError;
    private string? _quantityError;
    private string? _priceError;
    private string? _categoryError;

    private static readonly string[] Categories = { "Electronics", "Clothing", "Food", "Other" };

    protected override async Task OnInitializedAsync()
    {
        _products = await InventoryService.GetAllAsync();
    }

    private void StartEdit(Product product)
    {
        _editingProductId = product.Id;
        _editName = product.Name;
        _editQuantity = product.Quantity;
        _editUnitPrice = product.UnitPrice;
        _editCategory = product.Category;
        ClearErrors();
    }

    private void Cancel()
    {
        _editingProductId = null;
        ClearErrors();
    }

    private async Task SaveAsync()
    {
        if (!Validate())
            return;

        var product = _products!.First(p => p.Id == _editingProductId);
        product.Name = _editName;
        product.Quantity = _editQuantity;
        product.UnitPrice = _editUnitPrice;
        product.Category = _editCategory;

        await InventoryService.UpdateAsync(product);
        _editingProductId = null;
        ClearErrors();
    }

    private bool Validate()
    {
        ClearErrors();
        var valid = true;

        if (string.IsNullOrWhiteSpace(_editName))
        {
            _nameError = "Name is required.";
            valid = false;
        }

        if (_editQuantity < 0 || _editQuantity > 9999)
        {
            _quantityError = "Quantity must be between 0 and 9999.";
            valid = false;
        }

        if (_editUnitPrice <= 0)
        {
            _priceError = "Price must be greater than 0.";
            valid = false;
        }

        if (string.IsNullOrWhiteSpace(_editCategory) || !Categories.Contains(_editCategory))
        {
            _categoryError = "Category is required.";
            valid = false;
        }

        return valid;
    }

    private void ClearErrors()
    {
        _nameError = null;
        _quantityError = null;
        _priceError = null;
        _categoryError = null;
    }
}

