using sv_61594a677efa4f198e007d902b81bae0.Models;

namespace sv_61594a677efa4f198e007d902b81bae0.Services;

public class InventoryService
{
    private readonly List<Product> _products = new()
    {
        new Product { Id = 1, Name = "Wireless Mouse", Quantity = 150, UnitPrice = 29.99m, Category = "Electronics" },
        new Product { Id = 2, Name = "Cotton T-Shirt", Quantity = 300, UnitPrice = 14.99m, Category = "Clothing" },
        new Product { Id = 3, Name = "Organic Almonds", Quantity = 75, UnitPrice = 8.49m, Category = "Food" },
        new Product { Id = 4, Name = "USB-C Cable", Quantity = 500, UnitPrice = 12.99m, Category = "Electronics" },
        new Product { Id = 5, Name = "Winter Jacket", Quantity = 60, UnitPrice = 89.99m, Category = "Clothing" },
        new Product { Id = 6, Name = "Notebook & Pen Set", Quantity = 200, UnitPrice = 5.99m, Category = "Other" }
    };

    private readonly Lock _lock = new();

    public Task<List<Product>> GetAllAsync()
    {
        lock (_lock)
        {
            var copy = _products.Select(p => new Product
            {
                Id = p.Id,
                Name = p.Name,
                Quantity = p.Quantity,
                UnitPrice = p.UnitPrice,
                Category = p.Category
            }).ToList();
            return Task.FromResult(copy);
        }
    }

    public Task UpdateAsync(Product product)
    {
        lock (_lock)
        {
            var existing = _products.FirstOrDefault(p => p.Id == product.Id);
            if (existing is not null)
            {
                existing.Name = product.Name;
                existing.Quantity = product.Quantity;
                existing.UnitPrice = product.UnitPrice;
                existing.Category = product.Category;
            }
        }
        return Task.CompletedTask;
    }
}

